function eventModalView(){var n=ensureNarratorState(),inst=n.activeEvent;if(!inst)return'';var def=inst.definition,choices=def.choices&&def.choices.length?def.choices:[{id:'continue',label:'Continue',description:'Continue.',effects:[],visibleEffects:true}],effects=(def.immediateEffects||[]).filter(function(e){return e.playerVisible!==false;});return '<div class="event-modal-layer"><section class="event-modal"><div class="event-modal-head"><small>'+esc(titleCategory(def.category)+' / '+titleSeverity(def.severity)+(inst.preview?' / PREVIEW':''))+'</small><h2>'+esc(def.title)+'</h2></div><p class="event-short">'+esc((def.flair&&def.flair.shortText)||'The city shifts.')+'</p><p>'+esc((def.flair&&def.flair.longText)||'Providence has selected a data-driven event instance. Resolve it to continue the queue.').replace(/\n/g,' ')+'</p><div class="event-targets">'+inst.targets.map(function(t){return'<span>'+esc(t.fullName||t.name||t.id||'Target')+'</span>';}).join('')+'</div>'+(effects.length?'<div class="event-effects"><b>Visible effects</b>'+effects.map(function(e){return'<span>'+esc(e.displayText||e.variableId+' '+e.operation+' '+e.value)+'</span>';}).join('')+'</div>':'')+'<div class="event-choice-list">'+choices.map(function(c){return'<button class="event-choice" data-action="resolveEventChoice" data-choice="'+esc(c.id)+'"><b>'+esc(c.label)+'</b><span>'+esc(c.description||c.riskPreview||'Resolve this event.')+'</span></button>';}).join('')+'</div></section></div>';}
