function validateEventDefinition(def){var defs=currentEventDefinitions(),errs=[];if(!def.id)errs.push('Event ID is required.');if(defs.filter(function(e){return e.id===def.id;}).length>1)errs.push('Event ID must be unique.');if(EVENT_CATEGORIES.indexOf(def.category)<0)errs.push('Invalid category.');if(EVENT_SEVERITIES.indexOf(def.severity)<0)errs.push('Invalid severity.');if(!def.title)errs.push('Title is required.');if(!Number.isFinite(Number(def.baseWeight)))errs.push('Base weight must be numeric.');if(!Number.isFinite(Number(def.cooldownDays)))errs.push('Cooldown must be numeric.');(def.requirements||[]).forEach(function(r,i){if(r.variableId&&r.variableId!=='providence.condition'&&!variableById(r.variableId))errs.push('Requirement '+(i+1)+' variable missing: '+r.variableId);if(r.targetResolver&&EVENT_TARGET_RESOLVERS.indexOf(r.targetResolver)<0)errs.push('Requirement '+(i+1)+' target resolver invalid.');});(def.immediateEffects||[]).concat(def.afterEffects||[]).forEach(function(e,i){if(e.variableId&&!variableById(e.variableId))errs.push('Effect '+(i+1)+' variable missing: '+e.variableId);if(e.targetResolver&&EVENT_TARGET_RESOLVERS.indexOf(e.targetResolver)<0)errs.push('Effect '+(i+1)+' target resolver invalid.');});(def.choices||[]).forEach(function(c,i){if(!c.label)errs.push('Choice '+(i+1)+' needs a label.');});return errs;}
