function eventEditorView(){var n=ensureEventFrameworkState(),def=selectedEventDefinition(),valid=def?validateEventDefinition(def):['No event selected'];if(!def)return'<section class="providence-panel wide"><h3>Event Creator</h3><button data-action="createEventDef">Create Event</button></section>';return '<section class="providence-panel event-editor-shell wide"><div class="event-editor-head"><h3>Event Creator / Editor</h3><div><button data-action="createEventDef">Create</button><button data-action="duplicateEventDef">Duplicate</button><button data-action="deleteEventDef">Delete</button><button data-action="toggleEventDef">'+(def.enabled?'Disable':'Enable')+'</button><button class="primary" data-action="saveEventDef">Save</button></div></div><div class="event-editor-layout"><aside><div class="event-editor-filters"><input id="event-search" placeholder="Search events"><button data-action="filterEventDefs">Search</button></div>'+eventListView()+'</aside><main><div class="event-form-grid"><label>ID<input id="event-id" value="'+esc(def.id)+'"></label><label>Title<input id="event-title" value="'+esc(def.title)+'"></label><label>Category<select id="event-category">'+enumOptions(EVENT_CATEGORIES,def.category)+'</select></label><label>Severity<select id="event-severity">'+enumOptions(EVENT_SEVERITIES,def.severity)+'</select></label><label>Tags<input id="event-tags" value="'+esc((def.tags||[]).join(', '))+'"></label><label>Trigger<select id="event-trigger-mode">'+enumOptions(['weighted','condition_triggered','player_action','follow_up','scheduled'],def.triggerMode)+'</select></label><label>Base Weight<input id="event-base-weight" value="'+esc(def.baseWeight)+'"></label><label>Cooldown<input id="event-cooldown" value="'+esc(def.cooldownDays)+'"></label></div><label>Short Text<textarea id="event-short-text">'+esc((def.flair&&def.flair.shortText)||'')+'</textarea></label><label>Long Text<textarea id="event-long-text">'+esc((def.flair&&def.flair.longText)||'')+'</textarea></label><label>Debug Notes<textarea id="event-debug-notes">'+esc(def.debugNotes||'')+'</textarea></label><div class="builder-section"><h4>Effect Builder</h4>'+builderView('effect','Add Effect')+'<div class="builder-pills">'+(def.immediateEffects||[]).map(function(e){return'<span>'+esc((e.displayText||e.variableId)+' ['+e.targetResolver+']')+'</span>';}).join('')+'</div></div><div class="builder-section"><h4>Requirement Builder</h4>'+builderView('requirement','Add Requirement')+'<div class="builder-pills">'+(def.requirements||[]).map(function(r){return'<span>'+esc(r.variableId+' '+r.operator+' '+r.value)+'</span>';}).join('')+'</div></div><div class="builder-section"><h4>Weight Modifier Builder</h4>'+builderView('weight','Add Modifier')+'<div class="builder-pills">'+(def.weightModifiers||[]).map(function(w){return'<span>'+esc(w.variableId+' '+w.operator+' '+w.value+' +'+w.weightAdd)+'</span>';}).join('')+'</div></div><div class="event-editor-actions"><button data-action="previewEventDef">Preview Popup</button><button data-action="testEventDef">Test Trigger</button><button data-action="validateEventDef">Validate</button><button data-action="exportEventDefs">Export JSON</button><button data-action="importEventDefs">Import JSON</button></div><textarea id="event-import-export" class="event-json-box" placeholder="Import/export JSON appears here">'+esc(n.eventExportText||'')+'</textarea><div class="validation-box '+(valid.length?'bad':'good')+'">'+(valid.length?valid.map(esc).join('<br>'):'Valid event definition.')+'</div></main></div></section>';}
function graphPolyline(values,key,w,h,min,max){if(!values.length)return'';return values.slice().reverse().map(function(v,i){var x=values.length===1?w/2:i*w/(values.length-1),raw=Number(v[key]||0),y=h-((raw-min)/(max-min))*h;return(i?'L':'M')+x.toFixed(1)+' '+clamp(y,0,h).toFixed(1);}).join(' ');}
function providenceGraphView(){var data=(ensureNarratorState().metricHistory||[]).slice(0,30),labels=[['prosperity','Prosperity',0],['heat','Heat',1],['stability','Stability',2],['ambition','Ambition',3],['momentum','Momentum',4]];return '<svg class="providence-graph" viewBox="0 0 520 170"><rect width="520" height="170" rx="6"></rect>'+labels.map(function(row){return'<path class="graph-line graph-'+row[2]+'" d="'+graphPolyline(data,row[0],500,130,0,100)+'" transform="translate(10 20)"></path>';}).join('')+'<path class="graph-line graph-fortune" d="'+graphPolyline(data,'fortune',500,130,-100,100)+'" transform="translate(10 20)"></path></svg><div class="graph-legend">'+labels.map(function(row){return'<span class="graph-key graph-key-'+row[2]+'"><i></i>'+row[1]+'</span>';}).join('')+'<span class="graph-key graph-key-fortune"><i></i>Fortune</span></div><p class="graph-note">Most metrics use 0-100. Fortune uses -100 to +100 and is shown as the dashed line.</p>';}
function signedMetricBar(label,value){value=Math.round(clamp(value,-100,100));var neg=value<0,pos=value>0,width=Math.abs(value)/2;return'<div class="moral-meter '+(neg?'negative':pos?'positive':'neutral')+'"><span>'+esc(label)+'</span><b>'+(value>0?'+':'')+value+'</b><i><em style="'+(neg?'right:50%;width:'+width+'%':'left:50%;width:'+width+'%')+'"></em></i></div>';}
