function fortuneDailyDrift(){var n=ensureNarratorState(),pull=-(n.fortune||0)*.035,variance=(Math.random()-.5)*14;if(Math.abs(n.fortune)>75)variance+=(n.fortune>0?-1:1)*(4+Math.random()*8);n.fortune=clamp(Math.round((n.fortune||0)+pull+variance),-100,100);}
function pushMetricSnapshot(force){var n=ensureNarratorState();if(!Array.isArray(n.metricHistory))n.metricHistory=[];var stamp=state.day+'-'+state.time+'-'+(n.metricSerial||0);if(force)n.metricSerial=(n.metricSerial||0)+1,stamp=state.day+'-'+state.time+'-'+n.metricSerial;n.metricHistory.unshift({stamp:stamp,day:state.day,time:state.time,prosperity:n.prosperity,heat:n.heat,stability:n.stability,ambition:n.ambitionPressure,momentum:n.momentum,fortune:n.fortune});n.metricHistory=n.metricHistory.slice(0,90);}
