readVariable=function(variableId,ctx){ctx=ctx||{};var n=ensureNarratorState(),f=ensureFamilyState(),c=state.creatorCharacter||{},don=f.don||{},d=district((ctx.district&&ctx.district.id)||state.selected);if(variableId==='player.cash')return(state.dirty||0)+(state.clean||0);if(variableId==='player.dirtyCash')return state.dirty||0;if(variableId==='player.cleanCash')return state.clean||0;if(variableId==='player.debt')return c.lifeBurden&&/Debt/i.test(c.lifeBurden.name)?1000:0;if(variableId==='player.health')return don.health||80;if(variableId==='player.stress')return don.stress||0;if(variableId==='player.reputation')return don.reputation||0;if(variableId==='player.heat')return state.heat||0;if(variableId==='player.rank')return c.rank||don.title||'Associate';if(variableId==='player.age')return don.age||c.age||40;if(variableId.indexOf('player.skills.')===0){var k=skillRegistryKey(variableId.replace('player.skills.',''));return(c.skills&&c.skills[k])||0;}if(variableId.indexOf('player.attributes.')===0){var a=personalityRegistryKey(variableId.replace('player.attributes.',''));return(c.personalityStats&&c.personalityStats[a])||0;}if(variableId.indexOf('player.pillars.')===0){var p=capitalize(variableId.replace('player.pillars.',''));return(c.pillars&&c.pillars[p])||0;}if(variableId==='providence.prosperity')return n.prosperity;if(variableId==='providence.heat')return n.heat;if(variableId==='providence.stability')return n.stability;if(variableId==='providence.ambition')return n.ambitionPressure;if(variableId==='providence.momentum')return n.momentum;if(variableId==='providence.fortune')return n.fortune;if(variableId.indexOf('district.')===0)return d[variableId.replace('district.','')]||0;if(variableId.indexOf('relationship.')===0){try{return relBetween((ctx.target&&ctx.target.id)||'player','player')[relationshipKey(variableId.replace('relationship.',''))]||0;}catch(err){return 0;}}if(!state.frameworkVars)state.frameworkVars={};return state.frameworkVars[variableId];};
