providenceGraphView=function(){var data=(ensureNarratorState().metricHistory||[]).slice(0,45),labels=[['prosperity','Prosperity',0],['heat','Heat',1],['stability','Stability',2],['ambition','Ambition',3],['momentum','Momentum',4]];return '<svg class="providence-graph" viewBox="0 0 520 180"><rect width="520" height="180" rx="6"></rect><line class="graph-zero" x1="10" y1="90" x2="510" y2="90"></line>'+labels.map(function(row){return'<path class="graph-line graph-'+row[2]+'" d="'+signedGraphPolyline(data,row[0],500,150)+'" transform="translate(10 15)"></path>';}).join('')+'<path class="graph-line graph-fortune" d="'+signedGraphPolyline(data,'fortune',500,150)+'" transform="translate(10 15)"></path></svg><div class="graph-legend">'+labels.map(function(row){return'<span class="graph-key graph-key-'+row[2]+'"><i></i>'+row[1]+'</span>';}).join('')+'<span class="graph-key graph-key-fortune"><i></i>Fortune</span></div><p class="graph-note">All hidden metrics are shown on a -100 to +100 moral line. Zero is the center line; negative leans red, positive leans green.</p>';};
