function addSeverityBand(w,band,goodMetric){var hard=goodMetric?band:({highest:'lowest',high:'low',rising:'falling',neutral:'neutral',falling:'rising',low:'high',lowest:'highest'}[band]||band);if(hard==='highest'){w.Catastrophic*=2.8;w['Very Bad']*=2.15;w.Bad*=1.45;w.Good*=.52;w['Very Good']*=.32;}else if(hard==='high'){w.Catastrophic*=1.75;w['Very Bad']*=1.72;w.Bad*=1.28;w.Good*=.68;w['Very Good']*=.48;}else if(hard==='rising'){w['Very Bad']*=1.25;w.Bad*=1.18;w.Good*=.86;w['Very Good']*=.76;}else if(hard==='falling'){w.Good*=1.22;w['Very Good']*=1.16;w.Bad*=.92;w['Very Bad']*=.82;w.Catastrophic*=.72;}else if(hard==='low'){w.Good*=1.62;w['Very Good']*=1.45;w.Bad*=.72;w['Very Bad']*=.58;w.Catastrophic*=.42;}else if(hard==='lowest'){w.Good*=2.05;w['Very Good']*=1.82;w.Bad*=.52;w['Very Bad']*=.36;w.Catastrophic*=.18;}else{w.Neutral*=1.18;w.Bad*=1.05;w.Good*=1.03;}return w;}
