function applyDailyPlayerWear(){var n=ensureNarratorState(),f=ensureFamilyState(),don=f.don||{},heat=state.heat||0;if(n._wearDay===state.day)return;var stress=don.stress||0;if(stress>72)don.health=clamp(Math.round((don.health||80)-((stress-68)/18)),0,100);else if(stress<28)don.health=clamp(Math.round((don.health||80)+1),0,100);if(heat>55)don.reputation=clamp(Math.round((don.reputation||0)-((heat-50)/25)),0,100);n._wearDay=state.day;}
