classifyNarratorCondition=function(n){if(n.stability<-70||n.heat>78||(n.prosperity<-70&&n.stability<-35))return'Collapsing';if(n.stability<-25||n.prosperity<-35||n.heat>48)return'Struggling';if(n.prosperity>90&&n.stability>35&&n.heat<25)return'Dominant';if(n.prosperity>35&&n.stability>5)return'Prospering';return'Stable';};
currentSeverityWeights=function(n){var w=cloneWeights(providenceSeverityWeights.Stable);addSeverityBand(w,signedBand(n.prosperity),true);addSeverityBand(w,signedBand(n.heat),true);addSeverityBand(w,signedBand(n.stability),false);addSeverityBand(w,signedBand(n.ambitionPressure),true);if(n.fortune>45){w.Good*=1.18;w['Very Good']*=1.22;w.Bad*=.92;}if(n.fortune<-45){w.Bad*=1.18;w['Very Bad']*=1.18;w.Good*=.92;}if(n.momentum<-20){w.Neutral*=1.55;w.Bad*=.8;w.Good*=.85;w['Very Bad']*=.68;w.Catastrophic*=.45;}if(n.momentum>45){w.Bad*=1.18;w.Good*=1.08;w['Very Bad']*=1.14;}if(isRecoveryProtected(n)){w.Catastrophic*=.08;w['Very Bad']*=.32;w.Good*=1.5;w['Very Good']*=1.35;}Object.keys(w).forEach(function(k){w[k]=Math.max(0,Math.round(w[k]*100)/100);});return w;};
currentDomainWeights=function(n){var w=cloneWeights(providenceDomainWeights);if(n.stability<0){w.Social+=10;w.Mafia+=8;}if(n.familyOpinion<0)w.Social+=7;if(n.mafiaOpinion<0)w.Mafia+=9;if(n.ambitionPressure>20)w.Mafia+=8;if(n.heat>20){w.Trouble+=10;w.World+=4;}if(n.prosperity>20){w.Trouble+=7;w.Mafia+=5;}if(n.prosperity<-25){w.Opportunity+=10;w.Social+=5;}if(n.momentum<-20){w.Social+=5;w.Opportunity+=5;}if(n.futureSeeds.length)w['Follow-up']+=10;return w;};
