var readVariableProvidenceBase=readVariable;
readVariable=function(variableId,ctx){var n=ensureNarratorState(),f=ensureFamilyState(),don=f.don||{};if(variableId==='player.cash')return(state.dirty||0)+(state.clean||0);if(variableId==='player.familyOpinion')return metricFamilyOpinion();if(variableId==='player.mafiaOpinion')return metricMafiaOpinion();if(variableId==='player.health')return don.health===undefined?80:don.health;if(variableId==='player.stress')return don.stress||0;if(variableId==='player.reputation')return don.reputation||0;return readVariableProvidenceBase(variableId,ctx);};
