writeVariable=function(variableId,value,ctx){var current=(state.dirty||0)+(state.clean||0),desired=Math.round(Number(value)||0),don=ensureFamilyState().don;if(variableId==='player.cash'){var delta=desired-current;if(delta>=0)state.clean=Math.max(0,Math.round((state.clean||0)+delta));else{var loss=-delta,cleanLoss=Math.min(state.clean||0,loss);state.clean-=cleanLoss;state.dirty=Math.max(0,(state.dirty||0)-(loss-cleanLoss));}return;}if(variableId==='player.dirtyCash'){state.dirty=Math.max(0,desired);return;}if(variableId==='player.cleanCash'){state.clean=Math.max(0,desired);return;}if(variableId==='player.stress'){don.stress=clamp(desired,0,100);return;}if(variableId==='player.health'){don.health=clamp(desired,0,100);return;}if(variableId==='player.reputation'){don.reputation=clamp(desired,0,100);return;}writeVariableProvidenceBase(variableId,value,ctx);};
