function ensureCreatorState(){if(!state.creatorCharacter||state.creatorCharacter.version!==creatorDbVersion)state.creatorCharacter=generateCreatorCharacter('creator-v3-'+Date.now());if(!Array.isArray(state.creatorHistory))state.creatorHistory=[];state.creatorHistory=state.creatorHistory.filter(function(c){return c&&c.version===creatorDbVersion;});return state.creatorCharacter;}
function creatorTraitChip(t){var data=typeof t==='string'?creatorTraitByNameV3(t):t;if(!data)data={name:String(t),cat:'Trait',tip:'No tooltip recorded.',hints:{}};return '<span class="trait-chip cat-'+esc(data.cat.toLowerCase())+'" data-tip="'+creatorDataTip(data.name,data.cat,data.tip,data.hints,(data.excludes&&data.excludes.length?['Cannot coexist with: '+data.excludes.join(', ')]:null))+'">'+esc(data.name)+'</span>';}
