function creatorAssessmentPanel(c){return '<div class="overall-rating"><span>Overall Rating</span><b>'+esc(c.rating)+'</b><em>'+esc(c.archetype)+'</em></div>'+creatorRadar(c)+'<div class="creator-assessment"><b>'+esc(c.archetype)+'</b><span>'+esc(c.startDifficulty.name)+' - Score '+c.characterScore+'</span><p>'+esc(c.summary)+'</p></div><div class="creator-bullets good"><small>Strengths</small>'+c.strengths.map(function(x){return '<span>+ '+esc(x)+'</span>';}).join('')+'</div><div class="creator-bullets bad"><small>Weaknesses</small>'+c.weaknesses.map(function(x){return '<span>- '+esc(x)+'</span>';}).join('')+'</div>';}
