function trimCreatorHistory(){var locked=(state.creatorHistory||[]).filter(function(c){return c.locked;}),open=(state.creatorHistory||[]).filter(function(c){return !c.locked;}).slice(0,10);state.creatorHistory=locked.concat(open);}
