creatorAssessmentPanel=function(c){return '<div class="ability-pair"><div><span>Current Ability</span><b>'+esc(c.currentAbility)+'</b></div><div><span>Potential Ability</span><b>'+esc(c.potentialAbility)+'</b></div></div>'+creatorRadar(c)+creatorPillarCards(c)+'<div class="creator-assessment"><span>Best Pillar: '+esc(c.bestPillar)+'</span><span>Weakest Pillar: '+esc(c.weakestPillar)+'</span><p>'+esc(c.summary)+'</p></div><div class="creator-bullets good"><small>Strengths</small>'+c.strengths.map(function(x){return '<span>+ '+esc(x)+'</span>';}).join('')+'</div><div class="creator-bullets bad"><small>Weaknesses</small>'+c.weaknesses.map(function(x){return '<span>- '+esc(x)+'</span>';}).join('')+'</div>';}
creatorLegend=function(){return '<div class="creator-legend"><small>Character UI Legend</small><span>Skill Bar: 0-20 current ability; normal starts cannot roll 20.</span><span>Flames: gray crossed flame Hated, gray flame Uninterested, dash Neutral, one/two/three flames for Interested/Passionate/Obsessed.</span><span>Tooltip hints: +++ major positive to --- major negative. Trait colors live inside tooltips only.</span><span>Pentagon and pillar cards: Violence / Commerce / Influence / Control / Subterfuge.</span></div>';}
characterCreatorView=function(){var c=ensureCreatorState(),origin=creatorOriginsV3.find(function(o){return o.name===c.origin;})||{},identityTags=[creatorTag(c.origin,'Origin',origin.name?('Heritage and social background from '+c.origin+'.'):'Origin background.',null),creatorTag(c.originPlace,'Origin Place','Birthplace or first neighborhood identity.',null),creatorTag(c.originSocial,'Origin Affinity','Cultural, social, or neighborhood affinity.',null),creatorTag(c.past.name,'Past',c.past.tip,null)];return '<section class="creator-board v4"><div class="creator-head"><div><small>Starting playable character / full visibility</small><h2>CHARACTER CREATOR</h2></div><div class="creator-head-actions"><button class="inline" data-action="randomizeCharacter">Randomize</button><button class="primary inline" data-action="acceptCharacter">Use This Character</button></div></div><div class="creator-layout v4"><section class="creator-main"><div class="creator-card-top v4"><div class="portrait-stack">'+creatorPawn(c)+'<div class="appearance-line">'+esc([c.visual.appearance.body,c.visual.appearance.face,c.visual.appearance.eyes,c.visual.appearance.headwear].filter(function(x){return x&&x!=='None';}).join(' / '))+'</div></div><div><div class="creator-name"><h3>'+esc(c.fullName)+'</h3><span>'+esc(c.rank)+' - Age '+c.age+' - '+esc(c.gender)+'</span></div><div class="identity-tags">'+identityTags.join('')+'</div><section class="creator-bio lead"><h3>Biography</h3><p>'+esc(c.bio)+'</p></section></div></div><div class="creator-columns v4"><section><h3>Skills</h3><div class="creator-skills">'+creatorSkillNames.map(function(k){return creatorSkillRow(k,c.skills[k],c.passions[k]);}).join('')+'</div></section><section><h3>Personality Attributes</h3><div class="creator-hidden revealed">'+creatorPersonalityNames.map(function(k){return creatorPersonalityRow(k,c.personalityStats[k]);}).join('')+'</div></section><section><h3>Life Path</h3><div class="life-path-tags">'+creatorBackstoryButton(c.childhood,'Childhood')+creatorBackstoryButton(c.adulthood,'Adulthood')+'<button class="creator-tip-button burden"'+creatorTipAttrs('Life Burden',c.lifeBurden.name,c.lifeBurden.tip,{Severity:c.lifeBurden.severity},(c.lifeBurden.obsession||[]).length?['Rare Obsession: '+c.lifeBurden.obsession.join(', ')]:null)+'>'+esc(c.lifeBurden.name)+'</button></div><h3>Traits</h3><div class="creator-trait-row">'+c.traitData.map(creatorTraitChip).join('')+'</div></section></div></section><aside class="creator-summary"><h3>Assessment</h3>'+creatorAssessmentPanel(c)+creatorLegend()+'</aside><section class="creator-recent"><small>Recent Rolls</small>'+creatorHistoryRows()+'</section></div></section>';}
randomizeCharacter=function(){var prev=state.creatorCharacter;if(prev){prev=Object.assign({},prev);if(!Array.isArray(state.creatorHistory))state.creatorHistory=[];state.creatorHistory.unshift(prev);trimCreatorHistory();}state.creatorCharacter=generateCreatorCharacter('creator-v4-'+Date.now()+'-'+Math.random());state.stopReason='New starting character rolled: '+state.creatorCharacter.fullName;render();}
acceptCharacter=function(){var c=ensureCreatorState();ensureFamilyState();state.familyState.don.name=c.fullName;state.familyState.don.age=c.age;state.familyState.don.title=c.rank;state.familyState.don.initials=(c.first.charAt(0)+c.last.charAt(0)).toUpperCase();state.familyState.don.traits=c.traits.slice(0,4);state.familyState.don.note=c.bio;state.familyState.don.skills={violence:c.pillars.Violence,diplomacy:c.skills.Negotiation,cunning:c.skills.Intelligence,stewardship:c.skills.Finance,streetSense:c.skills['Street Smarts']};state.familyState.don.reputation=clamp(35+c.pillars.Influence*2+c.personalityStats.Pride*.12,0,100);state.familyState.don.stress=clamp(18+c.past.level*9+(c.lifeBurden.severity||0)*5,0,100);state.selectedFamilyPerson='don';state.messages.unshift({title:'Starting character accepted',type:'Family',day:state.day,time:state.time,importance:'important',read:false,body:c.fullName+' has been accepted as the current playable starting character.'});state.tab='Family';state.stopReason='Starting character accepted: '+c.fullName;render();}
function ensureFamilyState(){var defaults=defaultFamilyState();if(!state.familyState)state.familyState=defaults;if(!state.familyState.don)state.familyState.don=defaults.don;if(!Array.isArray(state.familyState.relatives))state.familyState.relatives=defaults.relatives;if(!Array.isArray(state.familyState.innerCircle))state.familyState.innerCircle=defaults.innerCircle;if(!state.familyState.hooks)state.familyState.hooks=defaults.hooks;if(!Array.isArray(state.familyState.decisionLog))state.familyState.decisionLog=[];if(!state.selectedFamilyPerson)state.selectedFamilyPerson='don';return state.familyState;}
function familyPeople(){var f=ensureFamilyState();return [f.don].concat(f.relatives).concat(f.innerCircle);}
function familyPerson(id){return familyPeople().find(function(p){return p.id===id;})||ensureFamilyState().don;}
function statMeter(label,value){value=clamp(Number(value||0),0,100);return '<div class="family-meter"><span>'+esc(label)+'</span><b>'+value+'</b><i><em style="width:'+value+'%"></em></i></div>';}
function traitChips(items){return '<div class="trait-row">'+(items||[]).map(function(t){return '<span>'+esc(t)+'</span>';}).join('')+'</div>';}
function familyPersonButton(p,group){return '<button class="person-row '+(state.selectedFamilyPerson===p.id?'selected':'')+'" data-action="selectFamilyPerson" data-id="'+p.id+'"><span class="portrait-token">'+esc(p.initials||p.name.slice(0,2))+'</span><span><b>'+esc(p.name)+'</b><small>'+esc(p.title||p.rank||group)+' - Loyalty '+(p.loyalty||0)+' - Competence '+(p.competence||0)+'</small></span></button>';}
function hookList(title,items){return '<div class="hook-box"><small>'+esc(title)+'</small>'+list(items||[],'None recorded.')+'</div>';}
function decisionButton(id,title,body,meta){return '<button class="decision-card" data-action="familyDecision" data-id="'+id+'"><b>'+esc(title)+'</b><span>'+esc(meta)+'</span><p>'+esc(body)+'</p></button>';}
function familyView(){var f=ensureFamilyState(),don=f.don,selected=familyPerson(state.selectedFamilyPerson),skills=don.skills||{},recent=f.decisionLog.slice(0,3).map(function(x){return x;});return '<section class="family-board"><div class="family-head"><div><small>Closest zoom / family table</small><h2>FAMILY</h2></div><p>The Don is not just a resource. His habits, loyalties, fears, and household politics are the first layer of the city simulation.</p></div><div class="family-layout"><section class="don-card"><div class="don-main"><span class="don-portrait">'+esc(don.initials)+'</span><div><small>'+esc(don.title)+' - Age '+don.age+'</small><h3>'+esc(don.name)+'</h3>'+traitChips(don.traits)+'</div></div><div class="family-meters">'+statMeter('Reputation',don.reputation)+statMeter('Stress',don.stress)+statMeter('Health',don.health)+statMeter('Cunning',skills.cunning)+statMeter('Diplomacy',skills.diplomacy)+statMeter('Street Sense',skills.streetSense)+statMeter('Stewardship',skills.stewardship)+statMeter('Violence',skills.violence)+'</div><p>'+esc(don.note)+'</p></section><section class="family-panel"><div class="panel-title"><small>Household</small><b>Relatives and succession pressure</b></div><div class="person-list">'+f.relatives.map(function(p){return familyPersonButton(p,'Relative');}).join('')+'</div></section><section class="family-panel"><div class="panel-title"><small>Inner circle</small><b>Ranks close enough to hurt you</b></div><div class="person-list">'+f.innerCircle.map(function(p){return familyPersonButton(p,'Inner Circle');}).join('')+'</div></section><aside class="family-dossier"><small>Selected person</small><div class="dossier-title"><span class="portrait-token large">'+esc(selected.initials||'??')+'</span><div><h3>'+esc(selected.name)+'</h3><p>'+esc((selected.title||selected.rank||'Family')+' - Age '+(selected.age||'?'))+'</p></div></div>'+traitChips(selected.traits)+'<div class="family-meters">'+statMeter('Loyalty',selected.loyalty)+statMeter('Competence',selected.competence)+'</div><p><b>Concern:</b> '+esc(selected.concern||'No current concern.')+'</p><p>'+esc(selected.note||'No private note recorded.')+'</p><div class="family-hooks">'+hookList('Favors',f.hooks.favors)+hookList('Grudges',f.hooks.grudges)+hookList('Secrets',f.hooks.secrets)+hookList('Ambitions',f.hooks.ambitions)+'</div></aside><section class="family-panel decisions"><div class="panel-title"><small>Personal decisions</small><b>Small choices with family weight</b></div><div class="decision-grid">'+decisionButton('sunday','Host Sunday Dinner','Pull relatives and captains into the house for food, silence, and repair.','Stress -8 / household loyalty +4')+decisionButton('bookkeeper','Lean on the Bookkeeper','Ask Rosa to quietly reconcile envelopes before the ledgers start telling stories.','Clean cash +250 / stress +3')+decisionButton('dispute','Settle a Family Dispute','Call Marco, Grace, and Enzo into the back room before pride becomes policy.','Reputation +3 / stress +6')+'</div><div class="decision-log"><small>Recent table memory</small>'+list(recent,'No personal decisions made yet.')+'</div></section></div></section>';}
function selectFamilyPerson(id){state.selectedFamilyPerson=id;render();}
function adjustPerson(id,key,delta){var p=familyPerson(id);if(p&&typeof p[key]==='number')p[key]=clamp(p[key]+delta,0,100);}
function familyDecision(id){var f=ensureFamilyState(),don=f.don,title='',body='',log='';if(id==='sunday'){don.stress=clamp(don.stress-8,0,100);adjustPerson('sofia','loyalty',4);adjustPerson('marco','loyalty',3);adjustPerson('lucia','loyalty',2);title='Sunday dinner held';body='The house stayed warm, the talk stayed careful, and several relatives left remembering why the name matters.';log='Sunday dinner cooled the house and lowered the Don stress.';}else if(id==='bookkeeper'){don.stress=clamp(don.stress+3,0,100);state.clean+=250;state.dirty=Math.max(0,state.dirty-500);adjustPerson('rosa','loyalty',2);title='Rosa corrected the books';body='Rosa found three bad envelopes and one useful pattern. The clean ledger improves, but the Don knows someone is shaving corners.';log='The bookkeeper cleaned $250 and flagged bad envelopes.';}else if(id==='dispute'){don.stress=clamp(don.stress+6,0,100);don.reputation=clamp(don.reputation+3,0,100);adjustPerson('marco','loyalty',-2);adjustPerson('grace','loyalty',2);adjustPerson('enzo','loyalty',-1);title='Family dispute settled';body='The Don ended the argument before it reached the street. Respect rose, but not everyone liked the verdict.';log='A family dispute raised reputation and shifted loyalties.';}else return;f.decisionLog.unshift('Day '+state.day+' '+state.time+': '+log);state.messages.unshift({title:title,type:'Family',day:state.day,time:state.time,importance:'important',read:false,body:body});state.stopReason='Family matter resolved: '+title;render();}
var bloodFamilyTypes=['Orphan','Only child','Big family','Broken family','Married with children','Widower','Estranged family','Criminal family','Political family','Poor immigrant family','Rich legacy family'];
var mafiaRankPlan=[
  {rank:'Boss',count:1,age:[45,72],bias:['Leadership','Connections','Negotiation','Intelligence']},
  {rank:'Underboss',count:1,age:[38,65],bias:['Leadership','Muscle','Street Smarts','Negotiation']},
  {rank:'Consigliere',count:1,age:[36,72],bias:['Negotiation','Intelligence','Connections','Finance']},
  {rank:'Capo',count:4,age:[32,62],bias:['Leadership','Connections','Street Smarts','Negotiation']},
  {rank:'Lieutenant',count:5,age:[28,54],bias:['Leadership','Muscle','Street Smarts']},
  {rank:'Senior Soldier',count:5,age:[30,58],bias:['Shooting','Muscle','Street Smarts','Discipline']},
  {rank:'Soldier',count:8,age:[23,48],bias:['Muscle','Shooting','Driving','Stealth','Street Smarts']},
  {rank:'Associate',count:9,age:[20,52],bias:['Finance','Connections','Driving','Negotiation','Stealth']},
  {rank:'Prospect',count:7,age:[18,34],bias:['Street Smarts','Driving','Muscle']},
  {rank:'Street Punk',count:8,age:[18,30],bias:['Street Smarts','Muscle','Stealth']}
];
function familyInitials(name){return String(name||'?').split(/\s+/).filter(Boolean).slice(0,2).map(function(p){return p.charAt(0);}).join('').toUpperCase()||'?';}
function familyBaseCharacter(seed,opts){opts=opts||{};var c=generateCreatorCharacter(seed),rand=seeded(seed+'-family');if(opts.age){c.age=opts.age[0]+Math.floor(rand()*(opts.age[1]-opts.age[0]+1));}if(opts.rank)c.rank=opts.rank;if(opts.relationship)c.relationship=opts.relationship;if(opts.status)c.status=opts.status;if(opts.gender)c.gender=opts.gender;c.id=opts.id||('char-'+seed.replace(/[^a-z0-9]+/gi,'-'));c.initials=familyInitials(c.fullName);c.loyalty=clamp(c.personalityStats.Loyalty+Math.floor(rand()*17)-8,0,100);c.competence=clamp(Math.round((c.pillars.Violence+c.pillars.Commerce+c.pillars.Influence+c.pillars.Control+c.pillars.Subterfuge)*3.5)+Math.floor(rand()*16),0,100);c.concern=opts.concern||familyConcern(c,rand);return c;}
function familyConcern(c,rand){var concerns=['Wants a clearer place in the hierarchy.','Carries old resentment quietly.','Needs money faster than pride admits.','Is watching who the Don trusts.','Would rather solve trouble privately.','Has useful contacts but expensive habits.'];if(c.lifeBurden&&c.lifeBurden.name!=='None')return c.lifeBurden.name+' keeps shaping their choices.';return pick(concerns,rand);}
function tuneMafiaMember(c,rank,rand,bias){bias=(bias||[]).filter(function(k){return c.skills[k]!==undefined;});bias.forEach(function(k){c.skills[k]=clamp(c.skills[k]+(rank==='Boss'?3:rank==='Underboss'||rank==='Consigliere'?2:1),0,18);});if(rank==='Boss'){c.currentAbility=c.currentAbility<'B'?'B':c.currentAbility;c.potentialAbility=c.potentialAbility<'A'?'A':c.potentialAbility;c.pillars.Control=clamp(c.pillars.Control+3,0,20);c.pillars.Influence=clamp(c.pillars.Influence+2,0,20);}if(rank==='Capo'||rank==='Lieutenant'){c.pillars.Control=clamp(c.pillars.Control+2,0,20);c.pillars.Influence=clamp(c.pillars.Influence+1,0,20);}if(rank==='Street Punk'||rank==='Prospect'){c.currentAbility=['F','D','C'][Math.floor(rand()*3)];c.potentialAbility=['B','B','A','C'][Math.floor(rand()*4)];}c.rank=rank;c.competence=clamp(c.competence+(rank==='Boss'?18:rank==='Underboss'||rank==='Consigliere'?12:rank==='Capo'?8:rank==='Street Punk'?-12:0),0,100);return c;}
function generateBloodFamily(seed){var rand=seeded(seed||('blood-'+Date.now())),f=ensureFamilyState(),donAge=f.don.age||ensureCreatorState().age||42,type=pick(bloodFamilyTypes,rand),members=[],origin=(state.creatorCharacter&&state.creatorCharacter.origin)||'Family',past=(state.creatorCharacter&&state.creatorCharacter.past&&state.creatorCharacter.past.name)||'Stable Past';function maybeOrg(member){var base=type==='Criminal family'?.5:type==='Political family'?.2:type==='Rich legacy family'?.16:.08;if(member.relationship==='Spouse / Partner')base+=.08;if(member.relationship==='Sibling'||member.relationship==='Cousin')base+=.06;if(rand()<base){member.orgRank=weightedPickCreator(rand,['Street Punk','Prospect','Associate','Soldier','Bookkeeper','Political Contact'],function(r){return r==='Street Punk'||r==='Prospect'?5:r==='Associate'?4:2;});}return member;}function add(rel,range,extra){extra=extra||{};var member=familyBaseCharacter(seed+'-'+rel+'-'+members.length,{id:'blood-'+rel.toLowerCase().replace(/[^a-z]+/g,'-')+'-'+members.length,relationship:rel,age:range,status:extra.status,gender:extra.gender,concern:extra.concern});members.push(maybeOrg(member));}var hasParents=type!=='Orphan',hasSpouse=['Married with children','Big family','Criminal family','Political family','Poor immigrant family','Rich legacy family'].indexOf(type)>=0||rand()>.48,childrenCount=type==='Married with children'?1+Math.floor(rand()*3):type==='Big family'?Math.floor(rand()*4):rand()>.72?1:0,siblingCount=type==='Only child'?0:type==='Big family'?3+Math.floor(rand()*4):type==='Broken family'?1+Math.floor(rand()*3):Math.floor(rand()*3),cousinCount=type==='Big family'||type==='Criminal family'?3+Math.floor(rand()*4):1+Math.floor(rand()*3);if(hasParents){add('Father',[donAge+20,Math.min(92,donAge+42)],{gender:'Male',status:type==='Broken family'&&rand()>.5?'Estranged':'Alive'});add('Mother',[donAge+18,Math.min(90,donAge+40)],{gender:'Female',status:type==='Broken family'&&rand()>.5?'Estranged':'Alive'});}else{add('Father',[donAge+20,Math.min(92,donAge+42)],{gender:'Male',status:'Unknown / deceased'});add('Mother',[donAge+18,Math.min(90,donAge+40)],{gender:'Female',status:'Unknown / deceased'});}if(donAge>34&&rand()>.25){add('Grandfather',[donAge+45,Math.min(99,donAge+70)],{gender:'Male',status:rand()>.55?'Deceased':'Alive'});add('Grandmother',[donAge+43,Math.min(99,donAge+68)],{gender:'Female',status:rand()>.5?'Deceased':'Alive'});}if(hasSpouse)add(type==='Widower'?'Late Partner':'Spouse / Partner',[Math.max(18,donAge-8),donAge+7],{status:type==='Widower'?'Deceased':type==='Estranged family'?'Estranged':'Alive'});for(var i=0;i<childrenCount;i++){var maxChild=Math.max(1,donAge-18),minChild=Math.max(1,donAge-48);add('Child',[minChild,Math.max(minChild,maxChild)],{status:type==='Estranged family'&&rand()>.5?'Estranged':'Alive'});}for(i=0;i<siblingCount;i++)add('Sibling',[Math.max(18,donAge-12),donAge+12],{status:type==='Estranged family'&&rand()>.45?'Estranged':'Alive'});var uncleCount=type==='Big family'?2+Math.floor(rand()*3):rand()>.5?1:0;for(i=0;i<uncleCount;i++)add(rand()>.5?'Uncle':'Aunt',[donAge+8,Math.min(92,donAge+34)]);for(i=0;i<cousinCount;i++)add('Cousin',[Math.max(18,donAge-18),donAge+18],{status:type==='Criminal family'?'In the life':'Alive'});return{type:type,origin:origin,past:past,members:members,generatedAt:'Day '+state.day+' '+state.time};}
function generateMafiaFamily(seed){var rand=seeded(seed||('mafia-'+Date.now())),members=[];mafiaRankPlan.forEach(function(plan){for(var i=0;i<plan.count;i++){var c=familyBaseCharacter(seed+'-'+plan.rank+'-'+i,{id:'mafia-'+plan.rank.toLowerCase().replace(/[^a-z]+/g,'-')+'-'+i,rank:plan.rank,relationship:plan.rank,age:plan.age});members.push(tuneMafiaMember(c,plan.rank,rand,plan.bias));}});return{members:members,generatedAt:'Day '+state.day+' '+state.time};}
function ensureFamilyPhase2(){var f=ensureFamilyState();if(!state.familySubtab)state.familySubtab='Blood Family';if(!f.bloodFamily)f.bloodFamily=generateBloodFamily('blood-init-'+Date.now());else if(typeof applyBloodFamilySurname==='function')applyBloodFamilySurname(f.bloodFamily);if(!f.mafiaFamily)f.mafiaFamily=generateMafiaFamily('mafia-init-'+Date.now());if(typeof mafiaOrganizationName==='function'){f.mafiaFamily.name=mafiaOrganizationName(f.mafiaFamily.culture);state.family=f.mafiaFamily.name;}if(!state.selectedFamilyProfile)state.selectedFamilyProfile='player';return f;}
function profileFromFamily(id){var f=ensureFamilyPhase2(),all=[familyPlayerCard()].concat((f.bloodFamily&&f.bloodFamily.members)||[]).concat((f.mafiaFamily&&f.mafiaFamily.members)||[]);return all.find(function(p){return p.id===id;})||all[0];}
function familyPlayerCard(){var f=ensureFamilyState(),don=f.don,c=state.creatorCharacter||{},rank=c.rank||don.title;return{id:'player',fullName:don.name,name:don.name,relationship:'Player Character',rank:rank,age:don.age,initials:don.initials,traits:don.traits||[],lifeBurden:c.lifeBurden||{name:'Personal burden unknown'},currentAbility:c.currentAbility||'?',potentialAbility:c.potentialAbility||'?',loyalty:100,competence:don.competence||88,concern:don.concern||'',skills:c.skills||{},pillars:c.pillars||don.skills||{},personalityStats:c.personalityStats||{},origin:c.origin,originPlace:c.originPlace,originSocial:c.originSocial,originTags:c.originTags,bio:don.note||''};}
function familyPortrait(c){var v=(c&&c.visual)||{},a=v.appearance||{},cols=a.colors||[v.suit||'#242424','#2a2119','#111'],skin=a.skin||v.skin||'#c99a73',hair=a.hair||v.hair||'#2b2018',hat=a.headwear&&a.headwear!=='None',scar=a.scar&&a.scar!=='None',beard=a.facialHair&&a.facialHair!=='None';return '<svg class="family-face" viewBox="0 0 64 72" aria-hidden="true"><rect x="5" y="5" width="54" height="54" rx="7" fill="#211915"></rect><rect x="8" y="8" width="48" height="48" rx="5" fill="#171717"></rect><path d="M18 28 L23 13 L43 13 L50 28 L46 47 L22 47 Z" fill="'+esc(hair)+'"></path>'+(hat?'<path d="M13 18 L51 18 L45 10 L20 10 Z" fill="'+esc(cols[2])+'"></path>':'')+'<path d="M20 24 L44 24 L50 35 L41 54 L26 54 L15 35 Z" fill="'+esc(skin)+'"></path><circle cx="26" cy="35" r="2.3" fill="#111"></circle><circle cx="39" cy="35" r="2.3" fill="#111"></circle><path d="M27 45 Q32 48 39 45" stroke="#111" stroke-width="2.4" fill="none" stroke-linecap="round"></path>'+(beard?'<path d="M22 45 Q32 60 43 45 L40 55 L27 55 Z" fill="#17120f" opacity=".55"></path>':'')+(scar?'<path d="M43 25 L36 39" stroke="#6b1e1e" stroke-width="2.4" stroke-linecap="round"></path>':'')+'<path d="M23 58 L41 58 L46 70 L18 70 Z" fill="'+esc(cols[0])+'"></path></svg>';}
function familyNode(c,kind){var name=c.fullName||c.name,meta=(c.relationship||c.rank||'Family')+' - Age '+(c.age||'?'),active=state.selectedFamilyProfile===c.id;return '<button class="family-node '+kind+' '+(active?'selected':'')+'" data-action="selectFamilyProfile" data-id="'+esc(c.id)+'"><span class="portrait-token">'+esc(c.initials||familyInitials(name))+'</span><b>'+esc(name)+'</b><small>'+esc(meta)+'</small></button>';}
function familyTreeNode(c,cls,pos){var name=c.fullName||c.name,rel=c.relationship||c.rank||'Family',rank=c.orgRank||(rel==='Player Character'?'Don':''),active=state.selectedFamilyProfile===c.id,style=pos?' style="left:'+pos.x+'px;top:'+pos.y+'px"':'';return '<button class="tree-person '+cls+' '+(active?'selected':'')+'"'+style+' data-action="selectFamilyProfile" data-id="'+esc(c.id)+'">'+familyPortrait(c)+'<b>'+esc(name)+'</b><small>'+esc(rel+' - '+(c.age||'?'))+'</small>'+(rank?'<em>'+esc(rank)+'</em>':'')+'</button>';}
