function blankRelationship(){return{'Opinion':0,Trust:45,Respect:45,Fear:10,Loyalty:40,Jealousy:5,Grudge:0,Familiarity:10,Admiration:5,Dependency:0,'Romantic Interest':0,tags:[]};}
