function mutateRumorText(text,rand){var variants=['People say '+text.toLowerCase()+'.',text.replace('traitor','anyone who disagrees').replace('failed','set up'),text+' Nobody agrees on the details.',text+' The story is getting uglier.'];return pick(variants,rand);}
