function socialTick(weeks){var s=ensureSocialState(),rand=seeded('tick-'+Date.now()+'-'+Math.random());weeks=weeks||1;s.week=(s.week||0)+weeks;s.memories.forEach(function(mem){mem.age+=weeks;var rel=relBetween(mem.from,mem.to),fade=Math.max(0,mem.decay*weeks);Object.keys(mem.effects||{}).forEach(function(k){var key=socialKey(k);if(rel[key]===undefined)return;var drift=mem.effects[k]>0?-fade:fade;rel[key]=clamp(Math.round(rel[key]+drift),key==='Opinion'?-100:0,100);});deriveRelTags(rel);});s.memories=s.memories.filter(function(mem){return mem.age<260&&mem.intensity-mem.age*mem.decay>4;});s.rumors.forEach(function(r){r.age+=weeks;r.spread+=Math.max(0,Math.floor(rand()*3));if(rand()<.35){r.mutation=clamp(r.mutation+5+Math.floor(rand()*15),0,100);r.accuracy=clamp(r.accuracy-3-Math.floor(rand()*8),0,100);r.text=mutateRumorText(r.text,rand);}});Object.keys(s.relationships).forEach(function(from){Object.keys(s.relationships[from]).forEach(function(to){var rel=s.relationships[from][to];if(rel.Jealousy>72&&rel.Grudge>35&&rel.tags.indexOf('Rival')<0){rel.tags.push('Rival');addMemory(from,to,'Jealous Rivalry Formed',48,.7,{Opinion:-10,Trust:-6,Grudge:10},['Rival']);}if(rel.Grudge>82&&rel.Opinion<-45&&rel.tags.indexOf('Blood Enemy')<0)rel.tags.push('Blood Enemy');rel.Familiarity=clamp(rel.Familiarity+weeks,0,100);});});maybeTraitDrift(rand);}
