function socialPressureScore(c,type,anchor){var rel=anchor?relBetween(c.id,anchor.id):blankRelationship(),score=10+Math.random()*4;if(type==='betrayal')score+=rel.Grudge*.8+rel.Jealousy*.55+(100-rel.Loyalty)*.35+socialValue(c,'Revenge')*.35+socialValue(c,'Freedom')*.12;if(type==='promotion')score+=socialValue(c,'Power')*.45+socialValue(c,'Status')*.35+(c.potentialAbility==='A'||c.potentialAbility==='S'?20:0)+rel.Admiration*.2;if(type==='playerAttention')score+=rel.Trust*.35+rel.Loyalty*.25+socialValue(c,'Status')*.34+socialValue(c,'Power')*.16+rel.Familiarity*.18;if(type==='argument')score+=rel.Grudge*.45+rel.Jealousy*.35+socialValue(c,'Honor')*.18+socialValue(c,'Power')*.12-rel.Trust*.12;if(type==='romanticSpark')score+=rel.Familiarity*.35+rel.Opinion*.4+socialValue(c,'Pleasure')*.25-rel.Grudge*.4;if(type==='familyDinner'||type==='funeral'||type==='wedding')score+=socialValue(c,'Family')*.55+rel.Familiarity*.25+rel.Loyalty*.2;if(type==='hospitalVisit')score+=socialValue(c,'Family')*.25+socialValue(c,'Security')*.35+rel.Trust*.35+rel.Dependency*.2;if(type==='prisonVisit')score+=rel.Loyalty*.5+socialValue(c,'Honor')*.35+rel.Trust*.45;if(type==='successfulHeist'||type==='failedHeist'||type==='crewBonding')score+=socialValue(c,'Money')*.18+socialValue(c,'Power')*.18+(c.orgRank||c.rank?18:0)+rel.Familiarity*.2;if(type==='sharedSecret')score+=rel.Trust*.6+rel.Dependency*.25+socialValue(c,'Security')*.25;if(type==='sharedDrink'||type==='gamblingNight'||type==='conversation')score+=rel.Opinion*.25+rel.Familiarity*.25+socialValue(c,'Pleasure')*.2;return Math.max(.1,score);}
function weightedSocialPick(pool,weightFn,rand,exclude){exclude=exclude||[];var items=pool.filter(function(c){return exclude.indexOf(c.id)<0;}),total=0,weighted=items.map(function(c){var w=Math.max(.01,weightFn(c));total+=w;return{c:c,w:w};}),roll=rand()*total;for(var i=0;i<weighted.length;i++){roll-=weighted[i].w;if(roll<=0)return weighted[i].c;}return weighted.length?weighted[weighted.length-1].c:null;}
function chooseSocialTargets(type,def,opts,rand){opts=opts||{};if(opts.targets&&opts.targets.length)return opts.targets.slice();var pool=socialPool(def.blood?'blood':def.mafia?'mafia':'all'),targets=[],anchor=familyPlayerCard();if(type==='betrayal'||type==='argument'||type==='romanticSpark'||type==='sharedSecret'||type==='hospitalVisit'||type==='prisonVisit'){var first=weightedSocialPick(pool,function(c){return socialPressureScore(c,type,anchor);},rand,[]);var second=weightedSocialPick(pool,function(c){return first?socialPressureScore(c,type,first):1;},rand,first?[first.id]:[]);targets=[first&&first.id,second&&second.id].filter(Boolean);}else{if(rand()>.28)targets.push('player');while(targets.length<(def.targets||2)){var next=weightedSocialPick(pool,function(c){return socialPressureScore(c,type,anchor);},rand,targets);if(!next)break;targets.push(next.id);}}return targets.slice(0,def.targets||2);}
var socialEventBaseV5=socialEvent;
socialEvent=function(type,opts){opts=opts||{};var def=socialEventDefs[type]||socialEventDefs.conversation,rand=seeded('smart-event-'+type+'-'+Date.now()+'-'+Math.random());opts.targets=chooseSocialTargets(type,def,opts,rand);var beforeRumors=ensureSocialState().rumors.length,entry=socialEventBaseV5(type,opts),s=ensureSocialState(),targets=(entry&&entry.targets)||[];if(type==='promotion'){var promoted=socialAllCharacters().find(function(c){return targets.indexOf(c.fullName)>=0;})||socialChar(opts.targets[0]);socialAllCharacters().forEach(function(c){if(c.id!==promoted.id&&c.rank){applyRelEffects(c.id,promoted.id,{Jealousy:10,Admiration:socialValue(c,'Power')>65?-3:4,Respect:4},socialValue(c,'Status')>65?1.25:.8);}});addRumor('crew',promoted.id,promoted.fullName+' is rising faster than people expected.',72,45);}if(type==='playerAttention'){var favored=socialAllCharacters().find(function(c){return targets.indexOf(c.fullName)>=0&&c.id!=='player';})||socialChar(opts.targets.filter(function(id){return id!=='player';})[0]||opts.targets[0]);socialAllCharacters().forEach(function(c){if(c.id!==favored.id&&c.id!=='player'&&(c.rank||c.orgRank)){var sensitivity=socialValue(c,'Status')>62?1.3:.85;applyRelEffects(c.id,favored.id,{Jealousy:12,Grudge:5,Admiration:-3,Opinion:-4},sensitivity);if(socialValue(c,'Power')>68)addMemory(c.id,favored.id,'Passed Over For Attention',34,.7,{Jealousy:8,Grudge:4,Opinion:-3},['Player Attention','Rival']);}});addPerceivedReputation(favored,'player','Boss Material',12);addRumor('crew',favored.id,favored.fullName+' has the Don\'s ear this week.',64,38);}if(type==='demotion'){addRumor('crew','player','The player humiliates people who disappoint the table.',54,48);}if(type==='moneyFavor'){addRumor('street','player','Money is flowing to favorites, not the loyal.',46,36);}if(type==='violentDispute'){socialAllCharacters().forEach(function(c){addPerceivedReputation(c,'player',socialValue(c,'Violence')>60?'Protector':'Tyrant',18);});}if(s.rumors.length===beforeRumors&&Math.random()<.18)addRumor('street','player','Something changed behind closed doors.',40,24);return entry;};
simulateSocialPeriod=function(weeks){for(var i=0;i<weeks;i++){var s=ensureSocialState(),tension=socialAllCharacters().reduce(function(max,c){var rels=s.relationships[c.id]||{};Object.keys(rels).forEach(function(k){max=Math.max(max,rels[k].Jealousy+rels[k].Grudge);});return max;},0),roll=Math.random();if(tension>135&&roll<.22)socialEvent('betrayal');else if(tension>100&&roll<.34)socialEvent('argument');else if(roll<.07)socialEvent('promotion');else if(roll<.12)socialEvent('moneyFavor');else if(roll<.18)socialEvent('playerAttention');else if(roll<.24)socialEvent('familyDinner');else if(roll<.28)socialEvent('hospitalVisit');else if(roll<.32)socialEvent('prisonVisit');else if(roll<.36)socialEvent('sharedSecret');else if(roll<.39)socialEvent('romanticSpark');else if(roll<.42)socialEvent('wedding');else if(roll<.49)socialEvent('conversation');else if(roll<.57)socialEvent('sharedDrink');else if(roll<.66)socialEvent('crewBonding');else if(roll<.73)socialEvent('gamblingNight');else if(roll<.79)socialEvent('successfulHeist');else if(roll<.84)socialEvent('failedHeist');else socialTick(1);}state.stopReason='Social simulation advanced '+weeks+' week'+(weeks===1?'':'s');render();};
function relationshipEdges(){var s=ensureSocialState(),edges=[];Object.keys(s.relationships).forEach(function(from){Object.keys(s.relationships[from]).forEach(function(to){var r=s.relationships[from][to];if(from===to)return;var strength=Math.max(Math.abs(r.Opinion),r.Trust,r.Grudge,r.Jealousy,r['Romantic Interest']);if(strength<58)return;edges.push({from:from,to:to,rel:r,type:r.Grudge>65?'Grudge':r.Jealousy>65?'Rivalry':r['Romantic Interest']>65?'Romance':r.Trust>74&&r.Opinion>45?'Friendship':r.Fear>70?'Fear':'Influence',strength:strength});});});return edges.sort(function(a,b){return b.strength-a.strength;}).slice(0,12);}
function hasRecentMemory(from,to,label,maxAge){return ensureSocialState().memories.some(function(m){return m.from===from&&m.to===to&&m.label===label&&m.age<=maxAge;});}
function spreadEventReputation(actor,target,type,rand){actor=actor&&actor.id?actor:socialChar(actor);target=target&&target.id?target:(target?socialChar(target):familyPlayerCard());socialAllCharacters().forEach(function(observer){var label='Dangerous',weight=12;if(type==='punishedTraitor'){label=socialValue(observer,'Security')>62||socialValue(observer,'Honor')>65?'Protector':'Tyrant';weight=18+Math.floor(rand()*16);}else if(type==='sabotage'){label=socialValue(observer,'Power')>64?'Clever':'Greedy';weight=14+Math.floor(rand()*12);}else if(type==='betrayal'){label=socialValue(observer,'Honor')>58?'Rat Suspect':'Dangerous';weight=18+Math.floor(rand()*18);}else if(type==='violence'){label=socialValue(observer,'Violence')>62?'Protector':'Cruel';weight=14+Math.floor(rand()*14);}addPerceivedReputation(observer,actor,label,weight);});}
function addDistortedRumor(source,target,truth,distortion,accuracy,intensity){addRumor(source,target,truth,accuracy,intensity);addRumor('street',target,distortion,Math.max(18,accuracy-34),Math.round((intensity||40)*.75));}
function escalateJealousRivalries(rand){var s=ensureSocialState(),incidents=0;Object.keys(s.relationships).forEach(function(from){Object.keys(s.relationships[from]).forEach(function(to){if(from===to||incidents>=2)return;var rel=s.relationships[from][to],actor=socialChar(from),target=socialChar(to),pressure=rel.Jealousy+rel.Grudge+(100-rel.Trust)*.35+socialValue(actor,'Revenge')*.25+socialValue(actor,'Power')*.15;if(pressure<138||hasRecentMemory(from,to,'Rivalry Escalated',10)||rand()>.18)return;var violent=socialValue(actor,'Violence')+rel.Fear*.25+rel.Grudge*.3,disloyal=100-rel.Loyalty+socialValue(actor,'Freedom')*.25;if(violent>92&&rand()<.38){addMemory(from,to,'Rivalry Escalated',46,.7,{Opinion:-8,Trust:-8,Grudge:8,Fear:8},['Rival','Violence']);socialEvent('violentDispute',{targets:[from,to],intensity:58});}else if(disloyal>82&&rand()<.35){addMemory(from,to,'Rivalry Escalated',50,.7,{Opinion:-10,Trust:-12,Grudge:10,Loyalty:-8},['Rival','Betrayal']);socialEvent('betrayal',{targets:[to,from],intensity:62});}else{addMemory(from,to,'Rivalry Escalated',42,.75,{Opinion:-9,Trust:-10,Grudge:12,Jealousy:6},['Rival','Sabotage']);socialEvent('sabotage',{targets:[from,to],intensity:52});addRumor('crew',target.id,actor.fullName+' may be undermining '+target.fullName+'.',48,42);}incidents++;});});return incidents;}
var socialTickRivalryBase=socialTick,rivalryEscalating=false;
socialTick=function(weeks){socialTickRivalryBase(weeks);if(rivalryEscalating)return;rivalryEscalating=true;try{escalateJealousRivalries(seeded('rivalry-escalation-'+Date.now()+'-'+Math.random()));}finally{rivalryEscalating=false;}};
var socialEventRumorBase=socialEvent;
socialEvent=function(type,opts){opts=opts||{};var entry=socialEventRumorBase(type,opts),rand=seeded('distorted-rumor-'+type+'-'+Date.now()+'-'+Math.random()),targets=(opts.targets||[]),actor=socialChar(targets[0]||'player'),target=socialChar(targets[1]||'player');if(type==='violentDispute'){addDistortedRumor(actor,target,actor.fullName+' used violence against '+target.fullName+'.',actor.fullName+' hurts anyone who disagrees.',58,54);spreadEventReputation(actor,target,'violence',rand);}else if(type==='betrayal'){addDistortedRumor(target,actor,target.fullName+' was betrayed by '+actor.fullName+'.',actor.fullName+' sells out anyone when the price is right.',62,58);spreadEventReputation(actor,target,'betrayal',rand);}else if(type==='sabotage'){addDistortedRumor(actor,target,actor.fullName+' undermined '+target.fullName+' behind the scenes.',actor.fullName+' is poisoning the whole crew.',46,48);spreadEventReputation(actor,target,'sabotage',rand);}return entry;};
function socialGraphPanel(){var s=ensureSocialState(),edges=relationshipEdges(),rumors=s.rumors.slice(0,3),events=s.eventLog.slice(0,4);return '<section class="social-graph"><div><small>Social Web</small><h3>Emergent Dynamics</h3></div><div class="graph-columns"><section><b>Strongest Links</b>'+(edges.length?edges.map(function(e){return'<button class="graph-link" data-action="selectFamilyProfile" data-id="'+esc(e.to)+'"><span>'+esc(e.type)+'</span><strong>'+esc(socialChar(e.from).fullName||e.from)+' -> '+esc(socialChar(e.to).fullName||e.to)+'</strong><em>'+Math.round(e.strength)+'</em></button>';}).join(''):'<p class="muted">No strong links yet.</p>')+'</section><section><b>Rumors</b>'+(rumors.length?rumors.map(function(r){return'<p><span>'+esc(r.text)+'</span><small>Accuracy '+r.accuracy+' / Spread '+r.spread+' / Mutation '+r.mutation+'</small></p>';}).join(''):'<p class="muted">No rumors circulating.</p>')+'</section><section><b>Recent Social Events</b>'+(events.length?events.map(function(e){return'<p><span>'+esc(e.type)+'</span><small>'+esc((e.targets||[]).join(', '))+'</small></p>';}).join(''):'<p class="muted">No recent events.</p>')+'</section></div></section>';}
