function opinionModifiersFor(c){var rel=relBetween(c.id,'player'),mods=[];function add(label,value){if(value)mods.push({label:label,value:Math.round(value)});}var relation={Father:35,Mother:35,Child:45,Sibling:20,'Spouse / Partner':50,'Late Partner':18,Cousin:10,Uncle:8,Aunt:8,Grandfather:12,Grandmother:12}[c.relationship]||0;add(c.relationship||'Relative',relation);add('Trust',Math.round((rel.Trust-50)*.55));add('Respect',Math.round((rel.Respect-50)*.45));add('Fear',Math.round(rel.Fear*.25));add('Jealousy',-Math.round(rel.Jealousy*.45));add('Grudge',-Math.round(rel.Grudge*.65));add('Familiarity',Math.round((rel.Familiarity-35)*.25));(rel.tags||[]).slice(0,3).forEach(function(t){add(t,t==='Rival'?-18:t==='Blood Enemy'?-45:t==='Friend'?18:t==='Best Friend'?35:t==='Spouse'?40:8);});mods=mods.filter(function(m){return Math.abs(m.value)>=1;}).slice(0,10);if(!mods.length)mods.push({label:'No strong personal modifiers',value:0});return mods;}
