function bloodFamilySummary(blood){var members=(blood.members||[]),all=members.concat([familyPlayerCard()]),total=all.length,involved=members.filter(function(m){return m.orgRank;}).length,originCounts={};all.forEach(function(m){var key=originNationalityOf(m);originCounts[key]=(originCounts[key]||0)+1;});var origins=Object.keys(originCounts).sort(function(a,b){return originCounts[b]-originCounts[a];}).slice(0,4).map(function(k){return k+' '+Math.round(originCounts[k]/total*100)+'%';}).join(' / ');var tags=[blood.type,blood.origin,blood.past,total+' relatives',involved+' linked to the life'].filter(Boolean);return '<div class="blood-summary family-summary"><div><small>Bloodline</small><h3>'+esc(blood.type)+'</h3><p>'+esc(origins||'Origin unknown')+'</p></div><div class="family-facts">'+tags.map(function(t){return'<span>'+esc(t)+'</span>';}).join('')+'</div><button class="inline" data-action="randomizeBloodFamily">Randomize Blood Family</button></div>';}
function recentFamilyEventsPanel(){var f=ensureFamilyPhase2(),bloodNames=(f.bloodFamily.members||[]).map(function(m){return m.fullName;}).concat([familyPlayerCard().fullName]),familyLabels=['Family Dinner','Wedding','Hospital Visit','Prison Visit','Funeral','Romantic Spark','Shared Secret'],events=(ensureSocialState().eventLog||[]).filter(function(e){return familyLabels.indexOf(e.type)>=0||(e.targets||[]).some(function(t){return bloodNames.indexOf(t)>=0;});}).slice(0,8);return '<aside class="recent-family-events"><small>Blood record</small><h3>Recent Family Events</h3>'+(events.length?events.map(function(e){return'<p><b>'+esc(e.type)+'</b><span>'+esc((e.targets||[]).join(', ')||'Family members')+'</span></p>';}).join(''):'<p class="muted">No notable blood-family events yet.</p>')+'</aside>';}
