function mafiaPerformance(member){var p=member.pillars||{},score=(member.competence||50)*.28+(p.Control||0)*2.1+(p.Influence||0)*1.7+(p.Commerce||0)*1.35+(p.Violence||0)*1.2+(mafiaStat(member,'Loyalty',50))* .14-(mafiaStat(member,'Notoriety Risk',40))* .08;return clamp(Math.round(score),8,99);}
function ensureStructuredMafia(org,bloodFamily){org.members=org.members||[];function hasRank(rank){return org.members.some(function(m){return normalizedMafiaRank(m.rank)===rank||m.rank===rank;});}function addRole(rank,age,bias){if(hasRank(rank))return;var seed='required-'+rank+'-'+Date.now()+'-'+Math.random(),rand=seeded(seed),c=familyBaseCharacter(seed,{id:'mafia-required-'+rank.toLowerCase().replace(/[^a-z]+/g,'-'),rank:rank,relationship:rank,age:age}),culture=org.culture||mafiaCultureForPlayer();if(typeof chooseMafiaOrigin==='function')applyMafiaCulture(c,culture,chooseMafiaOrigin(rand,culture,rank),rand,rank);org.members.push(tuneMafiaMember(c,rank,rand,bias||['Leadership','Negotiation','Intelligence']));}addRole('Boss',[54,76],['Leadership','Negotiation','Intelligence']);addRole('Underboss',[42,66],['Leadership','Street Smarts','Muscle']);addRole('Consigliere',[45,74],['Negotiation','Intelligence','Connections']);if(!hasRank('Capo'))addRole('Capo',[36,62],['Leadership','Street Smarts','Finance']);if(!hasRank('Soldier'))addRole('Soldier',[25,55],['Muscle','Shooting','Street Smarts']);if(!org.members.some(function(m){return mafiaRankMeta(m.rank).external;}))addRole('Bookkeeper',[34,68],['Finance','Intelligence','Connections']);org.members.forEach(function(m,i){m.rank=normalizedMafiaRank(m.rank);m.displayRank=displayMafiaRank(m.rank);m.performanceScore=m.performanceScore||mafiaPerformance(m);m.heatRisk=clamp(Math.round(mafiaStat(m,'Notoriety Risk',45)+(m.pillars&&m.pillars.Violence||0)*1.6),0,100);m.monthlyEarnings=m.monthlyEarnings||Math.max(120,Math.round((m.performanceScore*(mafiaRankMeta(m.rank).tier<3?55:mafiaRankMeta(m.rank).tier<5?38:22))));m.yearsInRank=m.yearsInRank||Math.max(1,Math.floor((m.age||35)/12)+i%4);m.specialization=m.specialization||((m.bestSkills&&m.bestSkills[0])||'Operations');m.assignment=m.assignment||(mafiaRankMeta(m.rank).external?'External asset':'Crew operations');});org.members.sort(mafiaRankSort);return org;}
